import React, { useState, useEffect } from "react";
import axios from "axios";
import "./App.css";

function App() {
  const [page, setPage] = useState("login");
  const [token, setToken] = useState(localStorage.getItem("token") || "");

  // ---------- Auth States ----------
  const [loginEmail, setLoginEmail] = useState("");
  const [loginPassword, setLoginPassword] = useState("");
  const [registerEmail, setRegisterEmail] = useState("");
  const [registerPassword, setRegisterPassword] = useState("");
  const [message, setMessage] = useState("");

  // Password toggle states
  const [showLoginPassword, setShowLoginPassword] = useState(false);
  const [showRegisterPassword, setShowRegisterPassword] = useState(false);

  // ---------- Expense States ----------
  const [expenses, setExpenses] = useState([]);
  const [description, setDescription] = useState("");
  const [amount, setAmount] = useState("");

  // ---------- Profile ----------
  const [profile, setProfile] = useState({ email: "" });

  // ---------------- AUTH ----------------
  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/api/auth/login", {
        email: loginEmail,
        password: loginPassword,
      });
      setToken(res.data.token);
      localStorage.setItem("token", res.data.token);
      setMessage("Login successful!");
      setPage("dashboard");
    } catch (err) {
      setMessage("Login failed: " + err.response.data.message);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/api/auth/register", {
        email: registerEmail,
        password: registerPassword,
      });
      setMessage("Registered successfully! Please log in.");
      setPage("login");
    } catch (err) {
      setMessage("Registration failed: " + err.response.data.message);
    }
  };

  const handleLogout = () => {
    setToken("");
    localStorage.removeItem("token");
    setPage("login");
  };

  // ---------------- EXPENSES ----------------
  useEffect(() => {
    if (token) {
      axios
        .get("http://localhost:5000/api/expenses", {
          headers: { Authorization: `Bearer ${token}` },
        })
        .then((res) => setExpenses(res.data))
        .catch((err) => console.error(err));
    }
  }, [token]);

  const addExpense = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(
        "http://localhost:5000/api/expenses",
        { description, amount },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setExpenses([...expenses, res.data]);
      setDescription("");
      setAmount("");
    } catch (err) {
      console.error(err);
    }
  };

  const deleteExpense = async (id) => {
    try {
      await axios.delete(`http://localhost:5000/api/expenses/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setExpenses(expenses.filter((e) => e._id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  // ---------------- PROFILE ----------------
  useEffect(() => {
    if (token) {
      axios
        .get("http://localhost:5000/api/auth/profile", {
          headers: { Authorization: `Bearer ${token}` },
        })
        .then((res) => setProfile(res.data))
        .catch((err) => console.error(err));
    }
  }, [token]);

  // ---------------- UI PAGES ----------------
  if (!token && page === "dashboard") {
    setPage("login");
  }

  return (
    <div className="container">
      {message && <div className="message">{message}</div>}

      {/* ----------- LOGIN ----------- */}
      {page === "login" && (
        <div className="auth-container">
          <div className="auth-card">
            <h2>Login</h2>
            <form onSubmit={handleLogin}>
              <div className="form-group">
                <label>Email</label>
                <input
                  type="email"
                  value={loginEmail}
                  onChange={(e) => setLoginEmail(e.target.value)}
                  required
                />
              </div>
              <div className="form-group">
                <label>Password</label>
                <div className="password-wrapper">
                  <input
                    type={showLoginPassword ? "text" : "password"}
                    value={loginPassword}
                    onChange={(e) => setLoginPassword(e.target.value)}
                    required
                  />
                  <button
                    type="button"
                    className="toggle-password"
                    onClick={() => setShowLoginPassword(!showLoginPassword)}
                  >
                    {showLoginPassword ? "🙈" : "👁️"}
                  </button>
                </div>
              </div>
              <button type="submit" className="btn-primary">
                Login
              </button>
              <button
                type="button"
                className="btn-secondary"
                onClick={() => setPage("register")}
              >
                Register
              </button>
            </form>
          </div>
        </div>
      )}

      {/* ----------- REGISTER ----------- */}
      {page === "register" && (
        <div className="auth-container">
          <div className="auth-card">
            <h2>Register</h2>
            <form onSubmit={handleRegister}>
              <div className="form-group">
                <label>Email</label>
                <input
                  type="email"
                  value={registerEmail}
                  onChange={(e) => setRegisterEmail(e.target.value)}
                  required
                />
              </div>
              <div className="form-group">
                <label>Password</label>
                <div className="password-wrapper">
                  <input
                    type={showRegisterPassword ? "text" : "password"}
                    value={registerPassword}
                    onChange={(e) => setRegisterPassword(e.target.value)}
                    required
                  />
                  <button
                    type="button"
                    className="toggle-password"
                    onClick={() =>
                      setShowRegisterPassword(!showRegisterPassword)
                    }
                  >
                    {showRegisterPassword ? "🙈" : "👁️"}
                  </button>
                </div>
              </div>
              <button type="submit" className="btn-primary">
                Register
              </button>
              <button
                type="button"
                className="btn-secondary"
                onClick={() => setPage("login")}
              >
                Back to Login
              </button>
            </form>
          </div>
        </div>
      )}

      {/* ----------- DASHBOARD ----------- */}
      {page === "dashboard" && (
        <div className="dashboard">
          <div className="dashboard-header">
            <h2>Expense Dashboard</h2>
            <div>
              <button
                className="btn-nav"
                onClick={() => setPage("profile")}
              >
                Profile
              </button>
              <button className="btn-logout" onClick={handleLogout}>
                Logout
              </button>
            </div>
          </div>

          <form className="expense-form" onSubmit={addExpense}>
            <h3>Add Expense</h3>
            <div className="form-row">
              <input
                type="text"
                placeholder="Description"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                required
              />
              <input
                type="number"
                placeholder="Amount"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                required
              />
              <button type="submit" className="btn-add">
                Add
              </button>
            </div>
          </form>

          <ul className="expense-list">
            {expenses.map((exp) => (
              <li key={exp._id} className="expense-item">
                <div className="expense-info">
                  <div className="expense-description">{exp.description}</div>
                  <div className="expense-amount">₹{exp.amount}</div>
                  <div className="expense-date">
                    {new Date(exp.createdAt).toLocaleDateString()}
                  </div>
                </div>
                <div className="expense-actions">
                  <button
                    className="btn-secondary"
                    onClick={() => deleteExpense(exp._id)}
                  >
                    Delete
                  </button>
                </div>
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* ----------- PROFILE ----------- */}
      {page === "profile" && (
        <div className="profile-section">
          <div className="profile-header">
            <h2>Profile</h2>
            <button className="btn-nav" onClick={() => setPage("dashboard")}>
              Back to Dashboard
            </button>
          </div>
          <div className="profile-form">
            <h3>Email</h3>
            <input type="text" value={profile.email} disabled />
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
